def validate(args, output):
    isWater = args[0]
    m = len(isWater)
    n = len(isWater[0]) if m else 0
    if not isinstance(output, list) or len(output) != m:
        return False
    for row in output:
        if not isinstance(row, list) or len(row) != n:
            return False
    for i in range(m):
        for j in range(n):
            h = output[i][j]
            if not isinstance(h, int) or h < 0:
                return False
            if isWater[i][j] == 1 and h != 0:
                return False
    for i in range(m):
        for j in range(n):
            for di, dj in ((1, 0), (0, 1)):
                ni, nj = i + di, j + dj
                if ni < m and nj < n:
                    if abs(output[i][j] - output[ni][nj]) > 1:
                        return False
    from collections import deque
    dist = [[-1] * n for _ in range(m)]
    dq = deque()
    for i in range(m):
        for j in range(n):
            if isWater[i][j] == 1:
                dist[i][j] = 0
                dq.append((i, j))
    while dq:
        i, j = dq.popleft()
        for di, dj in ((1, 0), (-1, 0), (0, 1), (0, -1)):
            ni, nj = i + di, j + dj
            if 0 <= ni < m and 0 <= nj < n and dist[ni][nj] == -1:
                dist[ni][nj] = dist[i][j] + 1
                dq.append((ni, nj))
    true_max = max(max(r) for r in dist)
    out_max = max(max(r) for r in output)
    return out_max == true_max

