function validate(args, output) {
    const isWater = args[0];
    const m = isWater.length;
    const n = m ? isWater[0].length : 0;
    if (!Array.isArray(output) || output.length !== m) return false;
    for (const row of output) {
        if (!Array.isArray(row) || row.length !== n) return false;
    }
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            const h = output[i][j];
            if (!Number.isInteger(h) || h < 0) return false;
            if (isWater[i][j] === 1 && h !== 0) return false;
        }
    }
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            for (const [di, dj] of [[1, 0], [0, 1]]) {
                const ni = i + di, nj = j + dj;
                if (ni < m && nj < n) {
                    if (Math.abs(output[i][j] - output[ni][nj]) > 1) return false;
                }
            }
        }
    }
    const dist = Array.from({length: m}, () => new Array(n).fill(-1));
    const q = [];
    let head = 0;
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            if (isWater[i][j] === 1) { dist[i][j] = 0; q.push([i, j]); }
        }
    }
    while (head < q.length) {
        const [i, j] = q[head++];
        for (const [di, dj] of [[1, 0], [-1, 0], [0, 1], [0, -1]]) {
            const ni = i + di, nj = j + dj;
            if (ni >= 0 && ni < m && nj >= 0 && nj < n && dist[ni][nj] === -1) {
                dist[ni][nj] = dist[i][j] + 1;
                q.push([ni, nj]);
            }
        }
    }
    let trueMax = 0, outMax = 0;
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            if (dist[i][j] > trueMax) trueMax = dist[i][j];
            if (output[i][j] > outMax) outMax = output[i][j];
        }
    }
    return outMax === trueMax;
}

